    "path": "src/GameMemory.cs",
    "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace AtelierRyza3Trainer\n{\n    /// <summary>\n    /// Provides low-level memory access to the Atelier Ryza 3 process.\n    /// Handles reading and writing of game values for the trainer.\n    /// </summary>\n    public static class GameMemory\n    {\n        private const string ProcessName = \"AtelierRyza3\";\n        private static IntPtr _processHandle;\n        private static int _processId;\n\n        // Kernel32 imports for memory operations\n        [DllImport(\"kernel32.dll\")]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint ProcessAllAccess = 0x1F0FFF;\n\n        /// <summary>\n        /// Attempts to attach to the running Atelier Ryza 3 process.\n        /// </summary>\n        /// <returns>True if successfully attached, false otherwise.</returns>\n        public static bool AttachToGame()\n        {\n            try\n            {\n                Process[] processes = Process.GetProcessesByName(ProcessName);\n                if (processes.Length == 0)\n                    return false;\n\n                _processId = processes[0].Id;\n                _processHandle = OpenProcess(ProcessAllAccess, false, _processId);\n                return _processHandle != IntPtr.Zero;\n            }\n            catch\n            {\n                return false;\n            }\n        }\n\n        /// <summary>\n        /// Detaches from the game process and releases the handle.\n        /// </summary>\n        public static void Detach()\n        {\n            if (_processHandle != IntPtr.Zero)\n            {\n                CloseHandle(_processHandle);\n                _processHandle = IntPtr.Zero;\n            }\n        }\n\n        /// <summary>\n        /// Reads a 4-byte integer from a specified memory address.\n        /// </summary>\n        /// <param name=\"address\">The memory address to read from.</param>\n        /// <returns>The integer value read, or 0 on failure.</returns>\n        public static int ReadInt(IntPtr address)\n        {\n            byte[] buffer = new byte[4];\n            if (ReadProcessMemory(_processHandle, address, buffer, 4, out _))\n            {\n                return BitConverter.ToInt32(buffer, 0);\n            }\n            return 0;\n        }\n\n        /// <summary>\n        /// Writes a 4-byte integer to a specified memory address.\n        /// </summary>\n        /// <param name=\"address\">The memory address to write to.</param>\n        /// <param name=\"value\">The integer value to write.</param>\n        /// <returns>True if successful, false otherwise.</returns>\n        public static bool WriteInt(IntPtr address, int value)\n        {\n            byte[] buffer = BitConverter.GetBytes(value);\n            return WriteProcessMemory(_processHandle, address, buffer, 4, out _);\n        }\n\n        /// <summary>\n        /// Reads a float from a specified memory address.\n        /// </summary>\n        /// <param name=\"address\">The memory address to read from.</param>\n        /// <returns>The float value read, or 0.0f on failure.</returns>\n        public static float ReadFloat(IntPtr address)\n        {\n            byte[] buffer = new byte[4];\n            if (ReadProcessMemory(_processHandle, address, buffer, 4, out _))\n            {\n                return BitConverter.ToSingle(buffer, 0);\n            }\n            return 0.0f;\n        }\n\n        /// <summary>\n        /// Writes a float to a specified memory address.\n        /// </summary>\n        /// <param name=\"address\">The memory address to write to.</param>\n        /// <param name=\"value\">The float value to write.</param>\n        /// <returns>True if successful, false otherwise.</returns>\n        public static bool WriteFloat(IntPtr address, float value)\n        {\n            byte[] buffer = BitConverter.GetBytes(value);\n            return WriteProcessMemory(_processHandle, address, buffer, 4, out _);\n        }\n    }\n}\n"
