    "path": "src/TrainerConfig.cs",
    "content": "using System;\nusing System.Collections.Generic;\n\nnamespace AtelierRyza3Trainer\n{\n    /// <summary>\n    /// Configuration class for the Atelier Ryza 3 trainer.\n    /// Stores memory addresses and feature flags for various cheats.\n    /// </summary>\n    public class TrainerConfig\n    {\n        // Memory addresses (example offsets, would be updated for actual game version)\n        public IntPtr GoldAddress { get; set; } = new IntPtr(0x00A1B2C0);\n        public IntPtr HpAddress { get; set; } = new IntPtr(0x00B3C4D0);\n        public IntPtr MpAddress { get; set; } = new IntPtr(0x00C5D6E0);\n        public IntPtr SpAddress { get; set; } = new IntPtr(0x00D7E8F0);\n        public IntPtr ExpAddress { get; set; } = new IntPtr(0x00E9FA00);\n        public IntPtr ItemCountAddress { get; set; } = new IntPtr(0x00F0A1B0);\n\n        // Feature toggles\n        public bool EnableInfiniteHp { get; set; } = false;\n        public bool EnableInfiniteMp { get; set; } = false;\n        public bool EnableInfiniteSp { get; set; } = false;\n        public bool EnableMaxGold { get; set; } = false;\n        public bool EnableMaxExp { get; set; } = false;\n        public bool EnableMaxItems { get; set; } = false;\n\n        // Hotkeys (virtual key codes)\n        public Dictionary<string, int> Hotkeys { get; set; } = new Dictionary<string, int>\n        {\n            { \"InfiniteHP\", 0x31 },   // 1 key\n            { \"InfiniteMP\", 0x32 },   // 2 key\n            { \"InfiniteSP\", 0x33 },   // 3 key\n            { \"MaxGold\", 0x34 },      // 4 key\n            { \"MaxExp\", 0x35 },       // 5 key\n            { \"MaxItems\", 0x36 },     // 6 key\n            { \"ToggleMenu\", 0x70 }    // F1 key\n        };\n\n        /// <summary>\n        /// Validates that all memory addresses are non-zero.\n        /// </summary>\n        /// <returns>True if all addresses are valid.</returns>\n        public bool ValidateAddresses()\n        {\n            return GoldAddress != IntPtr.Zero &&\n                   HpAddress != IntPtr.Zero &&\n                   MpAddress != IntPtr.Zero &&\n                   SpAddress != IntPtr.Zero &&\n                   ExpAddress != IntPtr.Zero &&\n                   ItemCountAddress != IntPtr.Zero;\n        }\n\n        /// <summary>\n        /// Resets all features to disabled.\n        /// </summary>\n        public void DisableAllFeatures()\n        {\n            EnableInfiniteHp = false;\n            EnableInfiniteMp = false;\n            EnableInfiniteSp = false;\n            EnableMaxGold = false;\n            EnableMaxExp = false;\n            EnableMaxItems = false;\n        }\n    }\n}\n"
