    "path": "src/CheatEngine.cs",
    "content": "using System;\nusing System.Threading;\n\nnamespace AtelierRyza3Trainer\n{\n    /// <summary>\n    /// Core cheat engine that applies modifications to the game based on TrainerConfig.\n    /// Runs a background thread to continuously update values when features are enabled.\n    /// </summary>\n    public class CheatEngine : IDisposable\n    {\n        private readonly TrainerConfig _config;\n        private Thread _cheatThread;\n        private bool _isRunning;\n        private bool _disposed;\n\n        public CheatEngine(TrainerConfig config)\n        {\n            _config = config ?? throw new ArgumentNullException(nameof(config));\n        }\n\n        /// <summary>\n        /// Starts the cheat engine background thread.\n        /// </summary>\n        public void Start()\n        {\n            if (_isRunning) return;\n\n            if (!GameMemory.AttachToGame())\n            {\n                throw new InvalidOperationException(\"Could not attach to Atelier Ryza 3 process. Ensure the game is running.\");\n            }\n\n            _isRunning = true;\n            _cheatThread = new Thread(CheatLoop)\n            {\n                IsBackground = true,\n                Name = \"CheatEngineThread\"\n            };\n            _cheatThread.Start();\n        }\n\n        /// <summary>\n        /// Stops the cheat engine and detaches from the game.\n        /// </summary>\n        public void Stop()\n        {\n            _isRunning = false;\n            _cheatThread?.Join(1000);\n            GameMemory.Detach();\n        }\n\n        /// <summary>\n        /// Main loop that applies cheats every 100ms.\n        /// </summary>\n        private void CheatLoop()\n        {\n            while (_isRunning)\n            {\n                try\n                {\n                    if (_config.EnableInfiniteHp)\n                    {\n                        // Set HP to max (example: 9999)\n                        GameMemory.WriteInt(_config.HpAddress, 9999);\n                    }\n\n                    if (_config.EnableInfiniteMp)\n                    {\n                        GameMemory.WriteInt(_config.MpAddress, 999);\n                    }\n\n                    if (_config.EnableInfiniteSp)\n                    {\n                        GameMemory.WriteInt(_config.SpAddress, 999);\n                    }\n\n                    if (_config.EnableMaxGold)\n                    {\n                        GameMemory.WriteInt(_config.GoldAddress, 999999);\n                    }\n\n                    if (_config.EnableMaxExp)\n                    {\n                        GameMemory.WriteInt(_config.ExpAddress, 999999);\n                    }\n\n                    if (_config.EnableMaxItems)\n                    {\n                        GameMemory.WriteInt(_config.ItemCountAddress, 99);\n                    }\n\n                    Thread.Sleep(100); // Refresh rate\n                }\n                catch\n                {\n                    // Silently handle errors to avoid crashing the trainer\n                    Thread.Sleep(500);\n                }\n            }\n        }\n\n        public void Dispose()\n        {\n            if (!_disposed)\n            {\n                Stop();\n                _disposed = true;\n            }\n        }\n    }\n}\n"
  },
