    "path": "src/Program.cs",
    "content": "using System;\nusing System.Runtime.InteropServices;\n\nnamespace AtelierRyza3Trainer\n{\n    /// <summary>\n    /// Main entry point for the Atelier Ryza 3 trainer console application.\n    /// Provides a simple text-based interface to toggle cheats.\n    /// </summary>\n    class Program\n    {\n        [DllImport(\"user32.dll\")]\n        private static extern short GetAsyncKeyState(int vKey);\n\n        private static TrainerConfig _config;\n        private static CheatEngine _cheatEngine;\n\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"Atelier Ryza 3: Alchemist of the End & the Secret Key Trainer\");\n            Console.WriteLine(\"============================================================\");\n            Console.WriteLine(\"Hotkeys:\");\n            Console.WriteLine(\"  F1 - Toggle this menu\");\n            Console.WriteLine(\"  1  - Infinite HP (toggle)\");\n            Console.WriteLine(\"  2  - Infinite MP (toggle)\");\n            Console.WriteLine(\"  3  - Infinite SP (toggle)\");\n            Console.WriteLine(\"  4  - Max Gold (toggle)\");\n            Console.WriteLine(\"  5  - Max EXP (toggle)\");\n            Console.WriteLine(\"  6  - Max Items (toggle)\");\n            Console.WriteLine(\"  ESC - Exit\");\n            Console.WriteLine();\n\n            _config = new TrainerConfig();\n            _cheatEngine = new CheatEngine(_config);\n\n            try\n            {\n                _cheatEngine.Start();\n                Console.WriteLine(\"Trainer started successfully. Attached to game.\");\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Error starting trainer: {ex.Message}\");\n                Console.WriteLine(\"Press any key to exit...\");\n                Console.ReadKey();\n                return;\n            }\n\n            bool running = true;\n            while (running)\n            {\n                // Check hotkeys using GetAsyncKeyState\n                if (GetAsyncKeyState(_config.Hotkeys[\"ToggleMenu\"]) != 0)\n                {\n                    Console.WriteLine(\"\\n[Menu toggled]\");\n                    Console.WriteLine($\"  Infinite HP: {_config.EnableInfiniteHp}\");\n                    Console.WriteLine($\"  Infinite MP: {_config.EnableInfiniteMp}\");\n                    Console.WriteLine($\"  Infinite SP: {_config.EnableInfiniteSp}\");\n                    Console.WriteLine($\"  Max Gold: {_config.EnableMaxGold}\");\n                    Console.WriteLine($\"  Max EXP: {_config.EnableMaxExp}\");\n                    Console.WriteLine($\"  Max Items: {_config.EnableMaxItems}\");\n                    System.Threading.Thread.Sleep(300); // Debounce\n                }\n\n                if (GetAsyncKeyState(_config.Hotkeys[\"InfiniteHP\"]) != 0)\n                {\n                    _config.EnableInfiniteHp = !_config.EnableInfiniteHp;\n                    Console.WriteLine($\"Infinite HP: {_config.EnableInfiniteHp}\");\n                    System.Threading.Thread.Sleep(200);\n                }\n\n                if (GetAsyncKeyState(_config.Hotkeys[\"InfiniteMP\"]) != 0)\n                {\n                    _config.EnableInfiniteMp = !_config.EnableInfiniteMp;\n                    Console.WriteLine($\"Infinite MP: {_config.EnableInfiniteMp}\");\n                    System.Threading.Thread.Sleep(200);\n                }\n\n                if (GetAsyncKeyState(_config.Hotkeys[\"InfiniteSP\"]) != 0)\n                {\n                    _config.EnableInfiniteSp = !_config.EnableInfiniteSp;\n                    Console.WriteLine($\"Infinite SP: {_config.EnableInfiniteSp}\");\n                    System.Threading.Thread.Sleep(200);\n                }\n\n                if (GetAsyncKeyState(_config.Hotkeys[\"MaxGold\"]) != 0)\n                {\n                    _config.EnableMaxGold = !_config.EnableMaxGold;\n                    Console.WriteLine($\"Max Gold: {_config.EnableMaxGold}\");\n                    System.Threading.Thread.Sleep(200);\n                }\n\n                if (GetAsyncKeyState(_config.Hotkeys[\"MaxExp\"]) != 0)\n                {\n                    _config.EnableMaxExp = !_config.EnableMaxExp;\n                    Console.WriteLine($\"Max EXP: {_config.EnableMaxExp}\");\n                    System.Threading.Thread.Sleep(200);\n                }\n\n                if (GetAsyncKeyState(_config.Hotkeys[\"MaxItems\"]) != 0)\n                {\n                    _config.EnableMaxItems = !_config.EnableMaxItems;\n                    Console.WriteLine($\"Max Items: {_config.EnableMaxItems}\");\n                    System.Threading.Thread.Sleep(200);\n                }\n\n                // Exit on Escape key\n                if (GetAsyncKeyState(0x1B) != 0) // VK_ESCAPE\n                {\n                    running = false;\n                }\n\n                System.Threading.Thread.Sleep(50);\n            }\n\n            _cheatEngine.Stop();\n            Console.WriteLine(\"Trainer stopped. Goodbye!\");\n        }\n    }\n}\n"
  },
