    "path": "tests/TrainerTests.cs",
    "content": "using System;\nusing Xunit;\n\nnamespace AtelierRyza3Trainer.Tests\n{\n    /// <summary>\n    /// Unit tests for the trainer components.\n    /// These tests validate configuration and engine behavior without attaching to a real process.\n    /// </summary>\n    public class TrainerTests\n    {\n        [Fact]\n        public void TrainerConfig_DefaultAddresses_AreNonZero()\n        {\n            var config = new TrainerConfig();\n            Assert.True(config.ValidateAddresses(), \"All default memory addresses should be non-zero
